INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00004wk8gbk3n8leu', '操作系统基本类型', '操作系统的基本类型包括单道批处理系统、多道批处理系统、分时系统、实时系统和微机操作系统。单道批处理系统内存中仅有一道程序，资源利用率低；多道批处理系统允许多道程序并发执行，提高资源利用率；分时系统通过时间片轮转实现交互性；实时系统要求快速响应外部事件；微机操作系统用于个人计算机。这些类型反映了操作系统在不同应用场景下的设计目标。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00005wk8glpja8u3q', '进程基本状态与转换', '进程的基本状态包括就绪状态、执行状态和阻塞状态。就绪状态指进程已获得除CPU外的所有资源，等待分配CPU；执行状态指进程正在占用CPU运行；阻塞状态指进程因等待某事件（如I/O完成）而暂停执行。状态转换包括：就绪→执行（调度）、执行→就绪（时间片用完或抢占）、执行→阻塞（等待事件）、阻塞→就绪（事件发生）。这是进程管理的基础。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00006wk8glvcn3phy', 'PCB作用与组成', '进程控制块（PCB）是操作系统用于管理进程的数据结构，作用是作为进程存在的唯一标志，实现进程的间断性运行，提供进程管理、调度、同步与通信所需的信息。PCB组成包括进程标识符、处理机状态（如寄存器内容）、进程调度信息（如优先级、状态）和进程控制信息（如程序地址）。每个进程对应一个PCB，是进程控制的核心。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00007wk8glgbxke6e', '调度算法目标', '调度算法的目标包括周转时间和带权周转时间。周转时间是指从作业提交到作业完成所经过的时间间隔，反映作业的整体执行效率；带权周转时间是周转时间与作业实际服务时间之比，用于衡量调度算法的公平性。其他目标还有响应时间、吞吐量等。这些指标用于评估不同调度算法的性能。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00008wk8g39kcih1a', '临界区访问原则', '临界区访问原则包括空闲让进、忙则等待、有限等待和让权等待。空闲让进指当无进程在临界区时，允许一个请求进入；忙则等待指当已有进程在临界区时，其他进程必须等待；有限等待指等待进程应在有限时间内进入；让权等待指等待进程应释放CPU，避免忙等。这些原则确保进程同步的正确性和效率。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f00009wk8gldgk0mci', '死锁必要条件', '死锁的必要条件包括互斥条件、请求和保持条件、不可抢占条件和循环等待条件。互斥条件指资源一次只能被一个进程使用；请求和保持条件指进程已持有资源又请求新资源；不可抢占条件指资源不能被强制剥夺；循环等待条件指存在进程-资源循环链。这四个条件同时满足时才会发生死锁，预防死锁需破坏其中之一。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f0000awk8gxec3h0ky', '动态分区分配算法', '动态分区分配算法用于管理内存中的可变分区，包括顺序分配算法和索引分配算法。顺序分配算法如首次适应、最佳适应、最差适应，通过遍历空闲分区链表进行分配；索引分配算法通过索引表管理空闲分区。这些算法影响内存利用率和分配效率，是内存管理的重要内容。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f0000bwk8gwdavuaj9', '虚拟存储器作用', '虚拟存储器的作用是突破物理内存容量限制，提高内存利用率和系统吞吐量，实现逻辑上的内存扩充。它通过将部分数据暂存到磁盘，使程序可以运行在比实际内存更大的地址空间，同时支持多道程序并发执行，减少内存碎片。虚拟存储器的实现依赖于请求分页或请求分段技术。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f0000cwk8gvi9475p8', '页面置换算法LRU', 'LRU（最近最久未使用）页面置换算法选择最近最长时间未被访问的页面进行置换，基于程序局部性原理。硬件支持包括寄存器和栈，用于记录页面访问时间。LRU算法性能较好，但实现开销较大，常用于分页系统中的页面置换，以减少缺页率。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqw8r1f0000dwk8gt7d4kka6', 'SPOOLing技术', 'SPOOLing（假脱机）技术通过磁盘作为缓冲，将独占设备（如打印机）改造为共享设备，实现虚拟设备。它利用输入/输出进程和磁盘缓冲区，使多个用户进程可以同时请求I/O操作，而实际设备顺序处理。SPOOLing提高了设备利用率和系统效率，是操作系统中设备管理的重要技术。', '操作系统', 0, 'cmqw8qry60003wk8gdd0zvk8l', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwajf2u0008wks8foaijk2f', '文件格式验证', '文件格式验证是指系统在接收用户上传文件时，检查文件扩展名或MIME类型是否符合预期格式（如PDF、DOCX）。若不符合，系统会返回错误提示，要求用户重新上传。该机制用于防止不兼容文件导致处理失败，提升系统健壮性。', '软件工程', 0, 'cmqwajcyq0007wks8utsfz370', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000dwks8m1l4i9vd', '操作系统基本类型', '操作系统按使用方式分为单道批处理系统、多道批处理系统、分时系统、实时系统和微机操作系统。单道批处理系统内存中仅一道程序，CPU利用率低；多道批处理系统允许多道程序并发，提高资源利用率；分时系统通过时间片轮转实现交互；实时系统要求快速响应外部事件。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000ewks82iz6x03l', '进程基本状态与转换', '进程具有就绪、执行和阻塞三种基本状态。就绪态指进程已获得除CPU外的所有资源；执行态指进程正在CPU上运行；阻塞态指进程因等待某事件而暂停。状态转换包括：就绪→执行（调度）、执行→就绪（时间片完）、执行→阻塞（等待事件）、阻塞→就绪（事件发生）。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000fwks8smpoui27', 'PCB作用与组成', '进程控制块（PCB）是进程存在的唯一标志，用于描述进程当前状态和控制进程运行。其作用包括：作为独立运行基本单位的标志、实现间断性运行、提供进程管理和调度所需信息、实现同步与通信。组成通常包括进程标识符、处理机状态、进程调度信息、进程控制信息。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000gwks836ap1yyr', '调度算法目标与类型', '调度算法目标包括周转时间（作业从提交到完成的时间间隔）和带权周转时间（周转时间与服务时间之比）。常见算法有：先来先服务（FCFS）、短作业优先（SJF）、优先级调度、轮转调度（RR）、多级队列调度、多级反馈队列调度等，各算法侧重公平性、响应时间或吞吐量。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000hwks82xf8wok0', '临界区访问原则', '临界区是访问共享资源的代码段，其访问需遵循四个原则：空闲让进（无进程在临界区时允许一个进程进入）、忙则等待（已有进程进入时其他必须等待）、有限等待（等待时间有限）、让权等待（等待时应释放CPU避免忙等）。这些原则保证互斥和避免死锁。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4op000iwks89iuykzcc', '信号量机制', '信号量是用于进程同步与互斥的整型变量，支持P（wait）和V（signal）操作。初始化时设定资源数量，P操作申请资源（若资源不足则阻塞），V操作释放资源并唤醒等待进程。信号量可解决经典同步问题（如生产者-消费者、读者-写者），是操作系统同步的重要工具。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4oq000jwks8ttkjlhk0', '死锁必要条件', '死锁发生的四个必要条件：互斥条件（资源一次只能被一个进程使用）、请求和保持条件（进程已持有资源又请求新资源）、不可抢占条件（资源只能由进程自愿释放）、循环等待条件（存在进程-资源循环链）。预防死锁需破坏其中任一条件。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4oq000kwks827xnfb0o', '页面置换算法LRU', 'LRU（最近最久未使用）算法选择最近最长时间未被访问的页面进行置换，基于程序局部性原理。实现需硬件支持（如寄存器或栈）记录页面访问时间。LRU性能较好但开销大，常用于虚拟存储器管理，能有效减少缺页率。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4oq000lwks8pt52ff36', 'SPOOLing技术', 'SPOOLing（假脱机操作）通过磁盘作为输入/输出缓冲区，将独占设备改造为共享虚拟设备。例如，多个进程同时打印时，输出数据先写入磁盘，再由打印守护进程依次打印，从而消除设备独占性，提高系统并发性。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwan4oq000mwks8li67nswy', '文件物理组织方式', '文件的物理组织方式决定文件在磁盘上的存储结构，包括连续组织（文件占用连续盘块，访问快但易产生碎片）、链接组织（通过指针链接盘块，消除碎片但随机访问慢）、索引组织（为每个文件建立索引表，支持直接访问，是常用方式）。', '操作系统', 0, 'cmqwamugc000cwks8f25sl15f', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0002wkyseiwse9dw', 'JavaEE平台', 'JavaEE（Java Enterprise Edition）是企业级Web开发平台，由一组规范（Specification）组成，包括JDBC、Servlet、JSP等13个技术规范。它定义了企业级应用的技术标准，但存在复杂、效率低、依赖服务器中间件等缺点。2017年更名为Jakarta EE。', 'JavaEE', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0003wkysmcmadla9', '应用服务器与Web容器', '应用服务器是JavaEE规范的具体实现，如Weblogic、JBoss，通常付费；Web容器（如Tomcat）只实现部分规范（如Servlet、JSP），是开源免费的轻量级服务器。应用服务器功能更全，但Web容器更轻便。', 'JavaEE', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0004wkysy2f8xec9', 'Tomcat核心配置文件', 'Tomcat有4个核心XML配置文件：context.xml（公用环境配置，自动加载）、web.xml（所有Web应用的父配置文件）、server.xml（核心配置，定义组件和端口）、tomcat-users.xml（配置用户和角色）。修改端口需编辑server.xml中的Connector元素。', 'Tomcat', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0005wkys56iipg5m', 'Tomcat架构组件', 'Tomcat架构基于组件：Server（JVM实例，监听8005端口接收关闭命令）、Service（关联引擎和连接器）、Connector（处理请求，支持HTTP、AJP等协议）、Engine（Servlet引擎，处理请求）、Host（虚拟主机，支持多域名）、Context（代表一个Web应用）。各组件层级清晰，共同处理请求。', 'Tomcat', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0006wkysn3z2hp3t', '虚拟主机配置', '虚拟主机允许在单一Tomcat实例上运行多个网站。通过修改server.xml添加多个Host元素，每个Host指定域名（name）和应用目录（appBase）。需在操作系统hosts文件中绑定域名和IP。请求根据域名匹配Host，未匹配则使用默认Host。', 'Tomcat', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0007wkysre814078', 'Servlet技术', 'Servlet是JavaEE平台下的服务端小程序，基于Java编写，运行在Web容器中。它采用单进程多线程模型，能高效处理请求。Servlet通过doGet/doPost方法处理HTTP请求，并生成响应。开发Servlet需继承HttpServlet，配置web.xml映射URL。', 'Servlet', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0008wkys2n0svib2', 'Tomcat请求处理流程', '用户请求经Connector接收，传给Engine，Engine匹配Host，Host匹配Context，Context调用Servlet处理。Servlet执行业务逻辑后，响应逐层返回至客户端。该流程体现了Tomcat组件间的协作。', 'Tomcat', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei0009wkyscp79vn1a', 'Tomcat Manager', 'Tomcat Manager是用于管理Tomcat和部署应用的Web应用，默认禁用。需在tomcat-users.xml中配置角色（如manager-gui）和用户。角色控制访问权限：manager-gui允许HTML GUI，manager-script允许文本界面等。', 'Tomcat', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcp3ei000awkys3ef8lr28', 'CGI与Servlet对比', 'CGI（公共网关接口）以进程方式处理请求，资源占用高，不同CGI不能共享资源。FastCGI改进但仍是进程模型。Servlet采用单进程多线程，资源利用率高，能共享数据，是更高效的服务器端技术。', 'Web开发', 0, 'cmqwcoufw0001wkysihucb3x6', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000dwkys81ewtyi3', 'JavaEE平台', 'JavaEE（Java Enterprise Edition）是用于企业级Web开发的平台，由一组规范（Specification）组成，包括JDBC、JNDI、EJB、Servlet等13个技术规范。它定义了企业级应用的技术标准，但存在复杂、效率低、依赖服务器中间件等缺点。2017年更名为Jakarta EE。', 'JavaEE', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000ewkysnonigwn5', '应用服务器与Web容器', '应用服务器是JavaEE规范的具体实现，如Weblogic、JBoss，通常付费且功能完整。Web容器（如Tomcat、Jetty）只实现部分规范（如Servlet、JSP），是轻量级、开源免费的服务器。两者区别在于实现规范的完整性和是否收费。', 'JavaEE', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000fwkysp7p4qunj', 'Tomcat核心配置文件', 'Tomcat有4个核心XML配置文件：context.xml（公用环境配置，自动加载）、web.xml（所有Web应用的父配置文件）、server.xml（核心配置，包含组件和端口）、tomcat-users.xml（配置用户和角色）。修改端口需编辑server.xml中的Connector元素。', 'Tomcat', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000gwkysqwl3e3bu', 'Tomcat架构组件', 'Tomcat架构由Server、Service、Connector、Engine、Host、Context等组件组成。Server代表JVM实例，Service包含一个Engine和多个Connector，Connector处理请求协议，Engine处理Servlet请求，Host代表虚拟主机，Context代表具体Web应用。这些组件在server.xml中配置。', 'Tomcat', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000hwkysc2jvi0pb', '虚拟主机配置', '虚拟主机允许在单一服务器上运行多个网站。在Tomcat中通过Host组件实现，需在server.xml中添加Host元素，指定name（域名）和appBase（应用目录），并修改操作系统的hosts文件进行域名解析。', 'Tomcat', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000iwkysehthpide', 'Servlet技术', 'Servlet是JavaEE平台下的服务端小程序，基于Java语言编写，运行在Web容器中，用于生成动态数据。其特点为单进程多线程，通过继承HttpServlet并重写doGet/doPost方法处理请求。Servlet需要在web.xml中配置映射。', 'Servlet', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000jwkysi3jsyr8m', 'Tomcat请求处理流程', '用户请求经Connector接收，传给Engine，Engine匹配Host，Host匹配Context，Context调用Servlet处理，生成响应后逐层返回。该流程体现了Tomcat组件间的协作关系。', 'Tomcat', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000kwkysk7zjkgfv', 'Tomcat Manager配置', 'Tomcat Manager是用于管理Tomcat和部署应用的Web应用，默认禁用。需在tomcat-users.xml中配置角色（如manager-gui）和用户，并解除webapps/manager/META-INF/context.xml中的访问限制。', 'Tomcat', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqwcq4ze000lwkyslssjtt42', 'Servlet继承结构', 'Servlet接口定义了init()、service()、destroy()等方法。GenericServlet实现了Servlet接口，HttpServlet继承GenericServlet并添加了doGet、doPost等方法。开发者通常继承HttpServlet来创建自己的Servlet。', 'Servlet', 0, 'cmqwcpxjc000cwkys6spp4fk4', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000ewkrwygpx4rqc', '操作系统类型', '操作系统基本类型包括单道批处理系统、多道批处理系统、分时系统、实时系统和微机操作系统。每种类型针对不同的应用场景和需求，如批处理系统适合批量任务处理，分时系统支持多用户交互，实时系统强调及时响应。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000fwkrwo1gwqjih', '操作系统功能', '操作系统主要功能包括处理机管理（进程控制、同步、通信和调度）、存储器管理（内存分配回收、保护、映射和扩充）、设备管理（缓存、分配和处理）、文件管理（空间、目录、读写和保护）以及接口管理（用户和程序接口）。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000gwkrwuh6rusnk', '程序并发执行', '程序并发执行具有三个特点：间断性（执行过程不连续）、失去封闭性（受其他程序影响）和不可再现性（相同输入可能产生不同输出）。这些特点使得并发程序设计变得复杂，需要操作系统进行有效管理。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000hwkrwm4b4syot', '进程状态', '进程有三种基本状态：就绪状态（等待CPU分配资源）、执行状态（正在CPU上运行）和阻塞状态（等待I/O或其他事件完成）。状态转换包括就绪→执行、执行→就绪、执行→阻塞和阻塞→就绪。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000iwkrw36jr1kqq', '进程控制块', 'PCB是进程存在的标志，包含进程标识符、调度信息、处理机状态和控制信息。它用于实现进程的间断性运行，提供进程管理所需信息，支持进程调度，并实现进程间的同步与通信。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000jwkrwf7poy224', '调度算法目标', '调度算法主要目标是优化周转时间（作业开始到完成的时间间隔）和带权周转时间（周转时间与服务时间之比）。好的调度算法能提高系统吞吐量、减少响应时间，确保公平性和系统资源利用率。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000kwkrwuxuszjl5', '调度算法', '常见调度算法包括先来先服务（FCFS）、短作业优先（SJF）、优先级调度、轮转调度（RR）、多级队列调度、多级反馈队列调度和基于公平原则的调度。每种算法适用于不同场景，各有优缺点。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000lwkrwqfb2f8zz', '临界区原则', '临界区访问遵循四个原则：空闲让进（资源空闲时允许进程进入）、忙则等待（资源忙时等待）、有限等待（等待时间有限）和让权等待（等待时放弃CPU）。这些原则确保互斥访问的正确性。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000mwkrwi4j4d74c', '信号量', '信号量是一种同步工具，用于控制进程对共享资源的访问。它通过初始化和P/V操作实现进程间的同步与互斥。信号量可以解决生产者-消费者问题、读者-写者问题等经典同步问题。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000nwkrw80nv67eb', '死锁条件', '死锁的四个必要条件是：互斥条件（资源独占）、请求和保持条件（持有资源同时请求新资源）、不可抢占条件（资源不可强制剥夺）和循环等待条件（进程间形成等待环）。打破任一条件可避免死锁。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000owkrwl8i94vm2', '动态分区分配', '动态分区分配算法包括顺序分配算法和索引分配算法。动态分区在程序运行时分配内存空间，提高了内存利用率，但会产生外部碎片，需要适当的合并和紧凑策略来优化内存使用。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000pwkrwzhisc0hq', '虚拟存储器', '虚拟存储器突破物理内存限制，提高内存利用率和系统吞吐量，实现逻辑上的内存扩充。它通过部分装入、请求调页和页面置换等技术，使程序可以使用比实际物理内存更大的地址空间。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000qwkrwduye1kmr', '页面置换算法', 'LRU（最近最少使用）页面置换算法替换最久未使用的页面，需要寄存器和栈的硬件支持。其他算法包括FIFO、OPT等。好的页面置换算法能减少缺页率，提高系统性能。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000rwkrwz77bj4yt', '抖动现象', '抖动是指系统中运行的进程过多，导致每个进程分配的物理块太少，频繁出现缺页的现象。预防方法包括采用局部置换策略、融入工作集算法、利用L=S准则调节缺页率、选择暂停进程等。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000swkrwwamyj4rc', 'I/O控制方式', 'I/O设备控制方式包括轮询的可编程I/O、中断驱动的I/O、直接存储器访问（DMA）和I/O通道方式。不同方式在效率、复杂度和适用场景上各有特点，从简单轮询到高效DMA逐步发展。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000twkrwnaal5q8s', '设备独立性', '设备独立性是指用户程序使用逻辑设备名而非物理设备名，由系统映射到实际物理设备。它提高了系统的可移植性和灵活性，简化了程序设计，便于设备更换和系统升级。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000uwkrwzawrbvsp', 'SPOOLing技术', 'SPOOLing（假脱机）技术将独占设备改造为共享设备，通过输入井和输出井实现。它提高了设备利用率，允许多个进程同时使用I/O设备，是虚拟设备技术的重要实现方式。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7m000vwkrw4j2mroli', '磁盘调度算法', '磁盘调度算法包括SSTF（最短寻道时间优先）和Scan（扫描）算法。SSTF选择距离磁头最近的请求，Scan则按固定方向扫描。好的调度算法能减少寻道时间，提高磁盘访问效率。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7n000wwkrww7dzluf8', '文件控制块', 'FCB用于管理文件系统中的大量文件，包含基本信息（文件名、位置、结构）、存取控制信息（权限）和使用信息（创建、修改时间等）。它是文件系统实现有效管理的基础数据结构。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxd2w7n000xwkrwkorcn8yp', '文件物理组织', '文件物理组织方式包括连续组织（文件连续存储）、链接组织（通过指针链接）和索引组织（使用索引表）。不同方式在访问效率、空间利用度和适用场景上各有优劣。', '操作系统', 0, 'cmqxd2bpo000dwkrwsgbm4c0u', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf140000wkt09d0drwlv', '虚拟存储器', '通过请求调页机制实现逻辑内存扩展，突破物理内存容量限制，使程序可以使用比实际物理内存更大的地址空间，提高内存利用率和系统性能。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf140001wkt01ci3anme', '进程间通信', '包括管道、消息队列、共享内存和套接字(Socket)等方式，实现不同进程间的数据交换和协同工作，是分布式系统和多任务处理的基础。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf140002wkt07yau09y5', 'ACID特性', '数据库事务的四个基本特性：原子性(不可分割)、一致性(状态正确)、隔离性(并发互不干扰)、持久性(永久保存)，确保数据操作的可靠性和一致性。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf140003wkt0gcyhhonu', '二叉树遍历', '包括前序、中序、后序和层序四种遍历方式，用于按特定顺序访问二叉树的所有节点，是树形数据结构操作的基础算法。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf140004wkt0ghmqu6sv', 'TCP三次握手', '通过SYN→SYN-ACK→ACK的序列建立连接，确保双方同步序列号并验证双方收发能力，是可靠网络通信的基础机制。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf150005wkt06p8b14z3', '欧拉公式', 'e^(iπ)+1=0，将自然常数e、虚数单位i和圆周率π联系起来，被誉为数学中最优美的公式之一，在复分析和信号处理中有广泛应用。', '数学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf150006wkt04j8zotr4', '排列组合公式', 'C(n,m)=n!/[m!(n-m)!]，用于计算从n个不同元素中取m个的组合数，是概率论和统计学的基础工具。', '数学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf150007wkt0q5icos5x', '摩根定律', '¬(A∧B)=(¬A)∨(¬B)，用于简化布尔表达式，是数字电路设计和逻辑推理中的重要法则，可减少逻辑门数量。', '数学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf150008wkt0fd0w52kk', '线性回归', '通过最小二乘法拟合数据，建立变量间的线性关系模型，用于预测连续变量，是统计学和机器学习的基础方法。', '数学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf150009wkt048dbuiyw', 'Dijkstra算法', '基于贪心策略求单源最短路径的算法，通过逐步确定最短路径，广泛应用于网络路由、导航系统和图论问题。', '数学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000awkt0nkmrykx0', '热力学第二定律', '熵增原理指出孤立系统熵永不减少，揭示了自然过程的方向性，是热力学和统计物理的核心原理。', '物理学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000bwkt0lbowx0eg', '波粒二象性', '光既表现波动性(干涉衍射)，又具粒子性(光电效应)，是量子力学的基本概念，挑战了经典物理的二元对立观点。', '物理学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000cwkt0d94fd29j', '元素周期表', '第118号元素Og(氡)是已知最重的稳定元素，元素周期表系统排列了所有已知元素，揭示了元素性质的周期性规律。', '物理学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000dwkt0amzyobh7', '牛顿第三定律', '作用力与反作用力大小相等，方向相反，是经典力学的基本定律，解释了物体间相互作用的本质。', '物理学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000ewkt0spcn5j3p', '孟德尔定律', '包括分离定律与自由组合定律，解释了性状遗传的规律，是现代遗传学的基础，奠定了基因理论的基础。', '生物学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000fwkt0m4jp5ytg', '马克思主义哲学', '三大规律：对立统一(矛盾发展)、质量互变(量变到质变)、否定之否定(螺旋上升)，是辩证法的核心内容。', '哲学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000gwkt03nrcvbmf', '古文明', '世界四大古文明：埃及、美索不达米亚、印度、中国，是人类早期文明的重要代表，对后世文化发展有深远影响。', '历史学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000hwkt00m46o3zd', '财务报表', '三大核心：资产负债表(财务状况)、利润表(经营成果)、现金流量表(现金变动)，是企业财务分析的基础工具。', '经济学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000iwkt0hnk3qruj', '帕累托原则', '二八定律指出20%因素导致80%结果，是经济学和管理学中的重要原理，用于资源分配和问题分析。', '经济学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdjf15000jwkt0ukjc8rie', '人工智能三要素', '数据、算法、算力是人工智能的三大支柱，数据提供学习材料，算法构建模型，算力支持计算，共同驱动AI模型训练。', '计算机科学', 0, 'cmqxd4zcd000zwkrw3x9ly8jm', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yq000kwkt0l90ynl06', '可见光谱', '人眼可接收到的电磁辐射，波长大约在380-780纳米之间。当波长从780nm向380nm变化时，人眼感知的颜色依次为红、橙、黄、绿、青、蓝、紫。不同波长范围对应不同颜色，如780nm-630nm为红色，430nm-380nm为紫色。', '光学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yq000lwkt0obrrou6f', '电磁波谱', '电磁波谱包括无线电波、红外线、可见光、X射线、宇宙射线等不同类型的电磁辐射。不同类型的电磁波具有不同的频率和波长范围，如可见光波长在380-780nm之间，而X射线波长更短。', '电磁学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yq000mwkt0jzroimm7', '视敏函数', '描述人眼对不同波长光的灵敏度差异的函数。定义为K(λ)=1/Pr(λ)，即在相同亮度感觉条件下，各波长光的辐射功率Pr(λ)的倒数。人眼对555nm的黄绿光最为敏感，这是视敏函数的最大值点。', '视觉科学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yq000nwkt0p79qhiaf', '相对视敏函数', '表示任意波长光的视敏函数与最大视敏函数的比值，用V(λ)表示。计算公式为V(λ)=K(λ)/Kmax=K(λ)/K(555)=Pr(555)/Pr(λ)。最大值为1，描述了人眼对不同波长光的相对敏感度。', '视觉科学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000owkt01zdiov2p', '明视觉与暗视觉', '人眼有两种视觉系统：明视觉(锥状细胞)和暗视觉(杆状细胞)。明视觉的相对视敏函数曲线峰值在555nm处，而暗视觉的曲线峰值在507nm处。两种视觉系统在不同光照条件下发挥作用，适应不同的环境亮度。', '视觉科学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000pwkt0s0vlnbt8', '色温', '用开尔文(K)表示的光源光谱成分特性，而非实际温度。色温高表示短波成分多，偏蓝绿色，光感偏冷；色温低表示长波成分多，偏红黄色，光感偏暖。色温是描述光源颜色特性的重要参数。', '光学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000qwkt0dthcr4i0', '加色法混色', '基于红绿蓝三基色的色彩混合原理。红色+绿色=黄色，红色+蓝色=紫色，蓝色+绿色=青色，红绿蓝三基色混合=白色。这种混色原理广泛应用于彩色显示器、电视等显示设备中。', '光学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000rwkt0lco8vr5a', '互补色', '两种混合后产生白色的颜色互为补色。如紫色+?=白色，青色+?=白色，黄色+?=白色。互补色在色彩理论中具有重要意义，用于理解色彩对比和色彩平衡。', '光学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000swkt00iv0xyae', '电视色彩系统', '彩色电视系统不仅要传递景物的亮度，还要传递色度(包括色调和色饱和度)。电视系统参数需根据人眼视觉特性选择，以确保重现图像质量满足人眼要求。黑白电视则只传递亮度信息。', '电视技术', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000twkt0slmddg6u', '视觉暂留', '人眼视觉的惰性现象，指图像在眼睛中成像后，其视觉信号不会立即消失，而是按指数规律衰减，完全消失需要约0.05s-0.2s的时间。这一原理是电影、动画等动态图像显示技术的基础。', '视觉科学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000uwkt0rzpeh6b8', '天线与波长关系', '天线长度与波长成正比，与频率成反比。频率越高，波长越短，需要更短的天线来达到相同辐射效果。通常天线长度约为波长的1/4或5/8，这种设计是为了最大化天线效率。', '电磁学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxdo9yr000vwkt0tb90lp2d', '光速公式', '光速c=λf，其中λ为波长，f为频率。光在真空中的速度约为3×10^8 m/s。这一基本公式描述了光波波长、频率与传播速度之间的关系，是光学和电磁学的基础公式。', '光学', 0, 'cmqxd1gws0001wkrwodmz1qz1', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p60003wknsgb8e2nto', '可见光', '人眼可接收到的电磁辐射，波长大约在380-780纳米之间。当波长由780nm向380nm变化时，人眼产生的颜色感觉依次是红、橙、黄、绿、青、蓝、紫七种颜色。可见光是电磁波谱中人眼能够感知的部分，是光学研究的基础。', '光学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70004wknsj45mmrl7', '电磁波谱', '电磁波谱是所有电磁辐射按波长或频率排列的连续谱系，包括无线电波、红外线、可见光、紫外线、X射线、伽马射线等。不同波段的电磁波具有不同的特性和应用，从长波无线电到短波宇宙射线，构成了完整的电磁辐射体系。', '电磁学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70005wkns3nt2vzs6', '视敏函数', '视敏函数K(λ)表示在相同亮度感觉条件下，各个波长的光的辐射功率Pr(λ)的倒数，即K(λ)=1/Pr(λ)。它描述了人眼对不同波长光的敏感程度，是视觉科学中的重要参数，用于评价光源的视觉效率。', '视觉科学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70006wknswrcpolzn', '相对视敏函数', '相对视敏函数V(λ)=K(λ)/Kmax=K(λ)/K(555)=Pr(555)/Pr(λ)，表示任意波长光的视敏函数与最大视敏函数的比值。在明亮环境下，人眼对波长为555nm的黄绿光最为敏感，V(λ)的最大值为1。', '视觉科学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70007wknsw78u4u3c', '明视觉与暗视觉', '明视觉主要由锥状细胞负责，其相对视敏函数曲线V(λ)的最大值在555nm处；暗视觉主要由杆状细胞负责，其相对视敏函数曲线V\'(λ)的最大值在507nm处。两种视觉系统适应不同的光照条件，具有不同的光谱敏感特性。', '视觉科学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70008wknsd2ax1xae', '色温', '色温用热力温标\'开尔文\'(K)表示，表示光源的光谱成分，而非实际温度。色温高表示短波成分多，偏蓝绿色，光越偏冷；色温低表示长波成分多，偏红黄色，光越暖。色温是评价光源颜色特性的重要参数。', '光学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p70009wkns8or0317l', '三基色原理', '红绿蓝三基色通过加色混合可以产生各种颜色：红色+绿色=黄色，红色+蓝色=紫色，蓝色+绿色=青色，红色+绿色+蓝色=白色。互为补色的两种色光混合也能产生白色，如紫色+黄色=白色。三基色原理是彩色显示技术的基础。', '光学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p7000awknswqtqvazo', '视觉暂留', '人眼的视觉具有惰性，图像在眼睛中成像后突然消失，视觉神经信号不会立即消失，而是按指数规律衰减，完全消失需要约0.05s-0.2s。视觉暂留现象是电影、电视等动态图像能够连续呈现的基础。', '视觉科学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p7000bwknsk4vs1i10', '电视系统', '电视系统分为黑白电视和彩色电视。黑白电视只传递景物的亮度，彩色电视同时传递亮度和色度（包括色调和色饱和度）。电视系统的参数设计必须基于人眼视觉特性，以满足人眼对图像质量的要求。', '电视技术', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p7000cwknsqcylt9zu', '天线与波长关系', '天线长度与波长成正比，与频率成反比。频率越高，波长越短，需要更短的天线来达到相同的辐射效果。通常天线长度约为波长的1/4或5/8，这种设计是为了最大化天线在特定频率下的发射和接收性能。', '电磁学', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3p7000dwkns8a0xdhlb', '峰值信噪比', 'PSNR(峰值信噪比)是客观评价图像质量的一种指标，通过计算原始图像与处理后图像之间的均方误差来衡量图像的保真度。PSNR值越高，表示图像质量越好，是图像处理领域常用的评价标准。', '图像处理', 0, 'cmqxejv0t0002wkns81uhmp2q', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3pv000gwknsihkq0or6', '可见光', '人眼可接收到的电磁辐射，波长大约在380-780纳米之间。当波长由780nm向380nm变化时，人眼产生的颜色感觉依次是红、橙、黄、绿、青、蓝、紫七种颜色。可见光是电磁波谱中人眼能够感知的部分，是光学研究的基础。', '光学', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3pw000hwkns4olpib9r', '电磁波谱', '电磁波谱是所有电磁辐射按波长或频率排列的连续谱系，包括无线电波、红外线、可见光、紫外线、X射线、伽马射线等。不同波段的电磁波具有不同的特性和应用，从长波无线电到短波宇宙射线，构成了完整的电磁辐射体系。', '电磁学', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3pw000iwkns7wle1evs', '视敏函数', '视敏函数K(λ)表示在相同亮度感觉条件下，各个波长的光的辐射功率Pr(λ)的倒数，即K(λ)=1/Pr(λ)。它描述了人眼对不同波长光的敏感程度，是视觉科学中的重要参数，用于评价光源的视觉效率。', '视觉科学', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
