INSERT INTO `knowledge_points` VALUES ('cmqxek3pw000kwknsor0gaq91', '明视觉与暗视觉', '明视觉主要由锥状细胞负责，其相对视敏函数曲线V(λ)的最大值在555nm处；暗视觉主要由杆状细胞负责，其相对视敏函数曲线V\'(λ)的最大值在507nm处。两种视觉系统适应不同的光照条件，具有不同的光谱敏感特性。', '视觉科学', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
