INSERT INTO `knowledge_points` VALUES ('cmqxek3pw000owknsw3geeyo5', '电视系统', '电视系统分为黑白电视和彩色电视。黑白电视只传递景物的亮度，彩色电视同时传递亮度和色度（包括色调和色饱和度）。电视系统的参数设计必须基于人眼视觉特性，以满足人眼对图像质量的要求。', '电视技术', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
INSERT INTO `knowledge_points` VALUES ('cmqxek3pw000pwknspxlzhycn', '天线与波长关系', '天线长度与波长成正比，与频率成反比。频率越高，波长越短，需要更短的天线来达到相同的辐射效果。通常天线长度约为波长的1/4或5/8，这种设计是为了最大化天线在特定频率下的发射和接收性能。', '电磁学', 0, 'cmqxek3pm000fwkns0wvil430', NULL);
