INSERT INTO `notes` VALUES ('cmqw78705000twkx8lscts5ku', '大学物理笔记', 'pdf', '这是大学物理的详细笔记内容...', NULL, '涵盖力学、热学、电磁学、光学等物理学基础知识。', '[\"物理学\", \"力学\", \"电磁学\"]', 'completed', '2026-06-27 10:10:08.117', '2026-06-27 10:10:08.117', 'cmqw786zi0000wkx87wp1ugk8', NULL, NULL);
INSERT INTO `notes` VALUES ('cmqw8qry60003wk8gdd0zvk8l', '期末复习资料(1)', 'docx', '填空、单选\n\n简答（不能仅有一些专业名词或术语，需要有一定的解释和说明）\n\n应用题（除非给定了表格填空，否则要有计算过程或者简要的说明）\n\n第一章  引论\n\n操作系统的基本类型（p7-11）\n\n		单道批处理系统、多道批处理系统、分时系统、实时系统、微机操作系统\n\n操作系统的主要功能（p22）\n\n		处理机管理功能（进程控制、进程同步、进程通信、调度）\n\n		储存器管理功能（内存分配和回收、内存保护、地址映射、内存扩充）\n\n		设备公路功能（缓存管理、设备分配、设备处理）\n		文件管理功能（文件储存空间管理、目录管理、文件的读写管理和保护）\n		接口管理功能（用户接口、程序接口）\n\n处理机管理功能（p23）\n\n		进程控制、进程同步、进程通信、调度\n\n第二章 进程的描述和控制\n\n程序并发执行的特点（p45-46）\n\n		间断性、失去封闭性、不可再现性\n\n进程的基本状态与转换（p47）\n\n		基本状态：就绪状态、执行状态、阻塞状态\n\n		转换：\n\nPCB的作用和组成（p51-52）\n\n		作用：\n\n				作为独立运行基本单位的标志\n\n				实现间断性运行方式\n\n				提供进程管理所需要的信息\n\n				提供进程调度所需要的信息\n\n				实现与其他进程的同步与通信\n\n		组成：\n\n				进程标识符、进程调度信息、\n\n处理机状态、进程控制信息\n\n第三章 处理机调度和死锁\n\n调度算法的目标（p81）：\n\n周转时间：开始到作业完成为止的这段时间间隔\n\n带权周转时间：作业的周转时间与系统为他提供服务的时间之比\n\n调度算法（p82-85）： \n\n		先来先服务调度算法\n\n		短作业优先调度算法\n\n		优先级调度算法\n		轮转调度算法\n\n		多级队列调度算法\n\n		多级反馈队列调度算法\n\n		基于公平原则的调度算法\n\n第四章 进程同步\n\n临界区访问的原则（p109）\n\n		空闲让进、忙则等待、有限等待、让权等待\n\n信号量及信号量的应用方法（p114）：\n\n信号量的定义：\n\n			\n\n初始化、\n\n应用（p145习题20）\n\n经典的进程同步问题（p120）看书\n\n死锁的必要条件（p134-135）\n\n			互斥条件、请求和保持条件\n\n			不可抢占条件、循环等待条件\n\n第五第六章 存储器管理和虚拟存储器\n\n动态分区分配算法（p160-161）\n\n			顺序分配算法、索引分配算法\n\n虚拟存储器的作用（p184）\n\n			突破内存容量限制\n\n			提高内存利用率和系统吞吐量\n\n			实现逻辑上的内存扩充\n\n页面置换算法（p194-195）：\n\nLRU：\n\n		LUR页面置换算法的硬件支持：\n\n			寄存器、栈\n\n请求分页式存储管理方式：地址映射（p208习题18）\n\n抖动和预防方法（p199-201）\n\n	抖动原因：	同时在系统中运行的进程太多，导致分配给每个进程的物理块太少，不能满足进程正常运行的基本要求，致使每个进程在运行时会频繁地出现缺页，必须请求系统将所缺之页调入内存。\n\n	预防方法：\n\n采取局部置换策略、把工作集算法融入处理机调度中、利用“L=S”准则调节缺页率、选择暂停的进程\n\n第七章 外设管理\n\nI/O系统的层次结构（p211）\n\n		用户层软件、与设备无关的I/O软件\n\n		设备驱动程序、中断处理程序\n\nI/O设备的控制方式（p220-223）\n\n使用轮询的可编程I/O方式、使用中断的可编程I/O方式、直接储存器访问（DMA）方式、I/O通道方式\n\n设备独立性（p233）：逻辑设备 \n\n		\n\nSPOOLing（p241）：虚拟设备\n\n磁盘调度算法（p252）：SSTF、Scan\n\n			SSTF:\n\nScan:\n\n	\n\n			\n\n第八第九章 文件系统\n\nFCB的作用和包含的信息（p269）\n\n		作用：对系统中大量文件施以有效的管理\n\n		信息：\n\n			基本信息类（文件名、文件物理位置、文件逻辑结构、文件的物理结构）\n\n			存取控制信息类（拥有者的存取权限、核准用户的存取权限、一般用户的存取权限）\n\n			使用信息类（建立日期、时间，上一次修改时间日期，当前使用的信息）\n\n文件的物理组织方式（p293）\n\n		连续组织方式、链接组织方式、索引组织方式', 'C:\\Users\\LEGION\\Desktop\\xuge\\server\\uploads\\4e70bb783dd179736c8a48521a46ffcb', '该笔记涵盖了操作系统课程的核心内容，包括操作系统的基本类型、功能、进程管理、处理机调度与死锁、进程同步、存储器管理、虚拟存储器、外设管理和文件系统。重点在于概念定义、算法原理和应用场景，适合用于考试复习。', '[\"操作系统\", \"进程管理\", \"存储器管理\", \"文件系统\", \"设备管理\"]', 'completed', '2026-06-27 10:52:34.687', '2026-06-27 10:52:46.938', 'cmqw7l6n80000wkfwdykdm7fo', NULL, NULL);
