INSERT INTO `questions` VALUES ('cmqw7872k0014wkx8uvnwpp19', '关于\"供需平衡\"，以下哪项描述最准确？', '\"[\\\"A. 正确描述\\\",\\\"B. 错误描述一\\\",\\\"C. 错误描述二\\\",\\\"D. 错误描述三\\\"]\"', 'A', '本题考察对\"供需平衡\"的理解。正确答案是A。', '经济学', 'cmqw786zn0003wkx80va7pp5a', 'choice', NULL);
INSERT INTO `questions` VALUES ('cmqw7872q0018wkx8wlfv7a7m', '关于\"边际效应\"，以下哪项描述最准确？', '\"[\\\"A. 正确描述\\\",\\\"B. 错误描述一\\\",\\\"C. 错误描述二\\\",\\\"D. 错误描述三\\\"]\"', 'A', '本题考察对\"边际效应\"的理解。正确答案是A。', '经济学', 'cmqw786zn0004wkx88mydauza', 'choice', NULL);
