INSERT INTO `questions` VALUES ('cmr7wzn440001wkg0900sd2kj', '比较可见光在电磁波谱中的位置及其与其他波段电磁波的主要区别，并说明可见光波长的变化如何影响人眼感知的颜色。', '[\"提示1：电磁波谱各波段的波长范围和特性\", \"提示2：可见光波长与颜色感知的关系\", \"提示3：可见光与其他波段电磁波的应用差异\"]', '可见光位于电磁波谱的中部，波长范围约为380-780纳米，介于红外线和紫外线之间。与其他波段相比，可见光能被人眼直接感知，而其他波段则需要借助仪器或特殊设备才能探测。可见光波长的变化直接影响人眼感知的颜色：当波长从780nm向380nm变化时，人眼依次感知到红、橙、黄、绿、青、蓝、紫七种颜色。这种颜色变化是由于不同波长的光刺激人眼视网膜上不同类型的感光细胞，产生不同的神经信号，最终在大脑中形成不同的颜色感觉。', '评分标准：1. 正确指出可见光在电磁波谱中的位置及其波长范围（2分）；2. 比较可见光与其他波段电磁波的主要区别（2分）；3. 准确描述波长变化与颜色感知的关系（3分）；4. 解释颜色感知的生理机制（3分）。', '光学', 'cmqxek3pv000gwknsihkq0or6', 'fill', NULL);
INSERT INTO `questions` VALUES ('cmr7wzn440003wkg0rqzde5zs', '解释视敏函数的物理意义及其在视觉科学中的应用，并分析为什么视敏函数在不同光照条件下会有差异。', '[\"提示1：视敏函数的定义和数学表达式\", \"提示2：视敏函数与视觉效率的关系\", \"提示3：光照条件对视敏函数的影响\"]', '视敏函数K(λ)表示在相同亮度感觉条件下，各个波长的光的辐射功率Pr(λ)的倒数，即K(λ)=1/Pr(λ)。它的物理意义是衡量人眼对不同波长光的敏感程度，值越大表示人眼对该波长的光越敏感。视敏函数在视觉科学中有多方面应用：用于评价光源的视觉效率；指导照明设计以优化视觉效果；帮助理解人眼对不同颜色光的感知差异；在颜色测量和色彩科学中作为基础参数。视敏函数在不同光照条件下会有差异，这是因为人眼有明视觉和暗视觉两种系统。在明亮环境下，主要由锥状细胞负责视觉，视敏函数峰值在555nm处；在暗环境下，主要由杆状细胞负责视觉，视敏函数峰值移至507nm处。这种差异反映了人眼对不同波长光的敏感度随光照条件变化的适应机制。', '评分标准：1. 准确解释视敏函数的定义和物理意义（3分）；2. 列举视敏函数在视觉科学中的至少3个应用（3分）；3. 分析视敏函数随光照条件变化的原因（3分）；4. 解释明视觉和暗视觉对视敏函数的影响（3分）。', '视觉科学', 'cmqxek3pw000hwkns4olpib9r', 'fill', NULL);
INSERT INTO `questions` VALUES ('cmr7wzn440005wkg06lmrredm', '推导相对视敏函数V(λ)的表达式，并解释为什么在明亮环境下人眼对波长为555nm的黄绿光最为敏感。', '[\"提示1：相对视敏函数的定义和推导过程\", \"提示2：555nm波长光的特殊性\", \"提示3：人眼感光细胞的分布特性\"]', '相对视敏函数V(λ)定义为任意波长光的视敏函数与最大视敏函数的比值，即V(λ)=K(λ)/Kmax。由于视敏函数K(λ)=1/Pr(λ)，且人眼对波长为555nm的光最为敏感，即K(555)为最大值，因此V(λ)=K(λ)/K(555)=Pr(555)/Pr(λ)。在明亮环境下，人眼对波长为555nm的黄绿光最为敏感，这主要是由于人眼锥状细胞的光谱响应特性。锥状细胞中的视锥蛋白对不同波长光的吸收效率不同，在555nm处达到峰值，这意味着在相同辐射功率下，555nm的光能产生最大的亮度感觉。此外，555nm接近太阳辐射光谱的峰值，这一波长在进化过程中可能被优先选择，以提高视觉效率。从物理角度看，555nm的光子能量适中，既能被感光分子有效吸收，又不会因能量过高而造成损伤，因此成为人眼最敏感的波长。', '评分标准：1. 正确推导相对视敏函数的表达式（3分）；2. 解释555nm波长光的特殊性及其原因（4分）；3. 分析人眼感光细胞的分布特性与视敏函数的关系（3分）；4. 从进化角度解释555nm敏感性的意义（2分）。', '视觉科学', 'cmqxek3pw000iwkns7wle1evs', 'fill', NULL);
INSERT INTO `questions` VALUES ('cmr7wzn450007wkg0jim17o5c', '比较明视觉与暗视觉的生理基础、光谱敏感特性及其适应机制，并举例说明两种视觉系统在实际生活中的应用。', '[\"提示1：明视觉与暗视觉的细胞基础\", \"提示2：两种视觉系统的光谱敏感曲线差异\", \"提示3：视觉适应机制及应用实例\"]', '明视觉主要由锥状细胞负责，而暗视觉主要由杆状细胞负责。锥状细胞主要集中在视网膜中央凹区域，数量约600-700万个，对颜色敏感，但在低光条件下反应差；杆状细胞分布在视网膜周边区域，数量约1.2亿个，对颜色不敏感，但在低光条件下敏感度高。两种视觉系统的光谱敏感特性不同：明视觉的相对视敏函数V(λ)峰值在555nm处，而暗视觉的相对视敏函数V\'(λ)峰值在507nm处。这种差异导致在不同光照条件下，人眼对不同颜色光的感知效率不同。视觉适应机制包括瞳孔调节、光化学适应和神经调节。瞳孔调节通过改变进入眼睛的光线量；光化学适应通过视色素的合成与分解来调整感光细胞的敏感性；神经调节则通过改变视觉通路中的信号传递效率来适应不同光照条件。在实际生活中，两种视觉系统的应用广泛：明视觉适用于阅读、驾驶等需要细节分辨的任务；暗视觉适用于夜间导航、星空观测等低光环境。例如，夜间驾驶时，驾驶员主要依靠杆状细胞来感知道路轮廓，而仪表盘照明则采用红光以减少对暗视觉的干扰。', '评分标准：1. 比较明视觉与暗视觉的细胞基础（3分）；2. 分析两种视觉系统的光谱敏感特性差异（3分）；3. 解释视觉适应机制的三个层面（3分）；4. 举例说明两种视觉系统在实际生活中的应用（3分）。', '视觉科学', 'cmqxek3pw000jwkns5mgpglcu', 'fill', NULL);
INSERT INTO `questions` VALUES ('cmr7wzn450009wkg0q8as3oky', '电磁波谱中的不同波段各有什么特性？请结合实际应用说明电磁波谱在科学研究和技术发展中的重要性。', '[\"提示1：电磁波谱各波段的特性比较\", \"提示2：电磁波谱在科学研究中的应用\", \"提示3：电磁波谱与技术创新的关系\"]', '电磁波谱是所有电磁辐射按波长或频率排列的连续谱系，各波段具有不同的特性和应用：无线电波（波长>1mm）穿透性强，用于通信和广播；微波（1mm-1m）能被水分子吸收，用于烹饪和雷达；红外线（700nm-1mm）产生热效应，用于夜视和热成像；可见光（380-780nm）能被眼睛直接感知，用于照明和成像；紫外线（10nm-380nm）能量较高，用于消毒和医疗；X射线（0.01-10nm）穿透力强，用于医学成像和安检；伽马射线（<0.01nm）能量最高，用于癌症治疗和核物理研究。电磁波谱在科学研究和技术发展中具有不可替代的重要性：首先，它提供了研究物质结构和性质的多种手段，如X射线晶体学用于解析分子结构；其次，它推动了通信技术的革命，从无线电到光纤通信；第三，它促进了医学诊断和治疗技术的进步，如MRI和放射治疗；第四，它拓展了人类对宇宙的认识，如射电天文学和X射线天文学；最后，它催生了众多新兴产业，如遥感技术、无线通信和医疗影像设备。电磁波谱的研究还揭示了电磁辐射的基本规律，为量子力学和相对论等现代物理学理论提供了实验基础。', '评分标准：1. 准确描述电磁波谱各波段的主要特性（3分）；2. 列举各波段至少一个实际应用（3分）；3. 分析电磁波谱在科学研究中的重要性（3分）；4. 说明电磁波谱对技术发展的影响（3分）；5. 举例说明电磁波谱研究对基础科学的贡献（3分）。', '电磁学', 'cmqxek3pw000kwknsor0gaq91', 'fill', NULL);
